#!/usr/bin/env node
/**
 * Copies `apps/core-api/openapi.json` into `apps/docs/public/openapi.json`
 * so the Astro build serves it statically at `/openapi.json`. The API
 * reference page at `src/pages/api/reference.astro` reads from that URL.
 *
 * Why a build step instead of an import: keeping the spec as a
 * runtime-fetchable file lets the docs page reload it without
 * rebuilding Astro, and keeps the HTML payload small (a multi-MB inlined
 * JSON would bloat every page).
 *
 * The source file is generated by `apps/core-api`'s `npm run gen:openapi`
 * and committed to this repo.
 *
 * `--strict` flag: production builds (`npm run build`) pass it so a
 * missing source file fails the build. Local dev (`npm run dev` /
 * `npm run start`) doesn't pass it — contributors working on prose pages
 * get a warning + a degraded API reference (404 on `/openapi.json`)
 * instead of being blocked from the dev server.
 */
import { existsSync, copyFileSync, mkdirSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const here = dirname(fileURLToPath(import.meta.url));
// apps/docs/scripts → apps/docs → apps → apps/core-api/openapi.json
const source = resolve(here, '..', '..', 'core-api', 'openapi.json');
const dest = resolve(here, '..', 'public', 'openapi.json');
const isStrict = process.argv.includes('--strict');

if (!existsSync(source)) {
    const message =
        `[copy-openapi] ${source} not found.\n` +
        '  It is generated by `npm run gen:openapi -w @antiphony/core-api` and committed.\n' +
        '  Regenerate it before building the docs API reference.';
    if (isStrict) {
        console.error(message);
        process.exit(1);
    }
    console.warn(`${message}\n  Proceeding without copying (dev mode — pass --strict to fail).`);
    process.exit(0);
}

mkdirSync(dirname(dest), { recursive: true });
copyFileSync(source, dest);
console.log(`[copy-openapi] ${source} → ${dest}`);
